chrome.runtime.onInstalled.addListener(()=>{console.log("Papertrail Extension Installed")});chrome.runtime.onMessage.addListener((t,n,e)=>{if(t.action==="capture_invoice")return c(t.data).then(()=>e({success:!0})).catch(a=>e({success:!1,error:a.message})),!0});async function c(t){const e=(await chrome.storage.local.get(["device_token"])).device_token;if(!e)throw new Error("Please add your device token in the Papertrail extension popup.");const o=await fetch("http://localhost:3000/api/capture",{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${e}`},body:JSON.stringify(t)});if(!o.ok){let r="Failed to capture receipt.";try{r=(await o.json()).error||r}catch{}throw new Error(r)}}
